import{_ as s,c as a,a as e,o as t}from"./app-CwFsTuGQ.js";const o={};function p(c,n){return t(),a("div",null,n[0]||(n[0]=[e(`<h1 id="redis-search" tabindex="-1"><a class="header-anchor" href="#redis-search"><span>Redis Search</span></a></h1><p>In the previous section, you learned how to search for entities using MySQL queries. However, MySQL-based searching can become a performance bottleneck in high-traffic applications. FluxaORM provides integration with the Redis Search engine, which offers much better performance for indexed queries.</p><h2 id="defining-the-redis-search-index" tabindex="-1"><a class="header-anchor" href="#defining-the-redis-search-index"><span>Defining the Redis Search Index</span></a></h2><p>By default, entities are not indexed in Redis Search. To enable Redis Search for an entity, you need two things:</p><ol><li>Add the <code>redisSearch</code> tag on the <code>ID</code> field, specifying the Redis pool to use for the search index.</li><li>Add the <code>searchable</code> tag to each field you want to include in the index.</li></ol><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">type</span> ProductEntity <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    ID    <span class="token builtin">uint64</span>  <span class="token string">\`orm:&quot;redisSearch=default&quot;\`</span></span>
<span class="line">    Name  <span class="token builtin">string</span>  <span class="token string">\`orm:&quot;required;searchable&quot;\`</span></span>
<span class="line">    Price <span class="token builtin">float64</span> <span class="token string">\`orm:&quot;searchable;sortable&quot;\`</span></span>
<span class="line">    Age   <span class="token builtin">uint32</span>  <span class="token string">\`orm:&quot;searchable;sortable&quot;\`</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>In this example, <code>Name</code>, <code>Price</code>, and <code>Age</code> are indexed in Redis Search on the <code>default</code> Redis pool.</p><h3 id="sortable-fields" tabindex="-1"><a class="header-anchor" href="#sortable-fields"><span>Sortable Fields</span></a></h3><p>By default, indexed fields are not sortable. Add the <code>sortable</code> tag to make a field available for sorting in search queries:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">type</span> UserEntity <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    ID        <span class="token builtin">uint64</span> <span class="token string">\`orm:&quot;redisSearch=default&quot;\`</span></span>
<span class="line">    Name      <span class="token builtin">string</span> <span class="token string">\`orm:&quot;required;searchable&quot;\`</span></span>
<span class="line">    Age       <span class="token builtin">uint32</span> <span class="token string">\`orm:&quot;searchable;sortable&quot;\`</span> <span class="token comment">// can be used in SortBy()</span></span>
<span class="line">    CreatedAt time<span class="token punctuation">.</span>Time <span class="token string">\`orm:&quot;searchable&quot;\`</span>        <span class="token comment">// NOT sortable</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="entity-field-mapping" tabindex="-1"><a class="header-anchor" href="#entity-field-mapping"><span>Entity Field Mapping</span></a></h2><p>The table below shows how Go field types are mapped to Redis Search index field types:</p><table><thead><tr><th>Go Type</th><th>Redis Search Type</th><th>Notes</th></tr></thead><tbody><tr><td><code>int</code>, <code>int8</code>, <code>int16</code>, <code>int32</code>, <code>int64</code></td><td>NUMERIC</td><td></td></tr><tr><td><code>uint</code>, <code>uint8</code>, <code>uint16</code>, <code>uint32</code>, <code>uint64</code></td><td>NUMERIC</td><td></td></tr><tr><td><code>float32</code>, <code>float64</code></td><td>NUMERIC</td><td></td></tr><tr><td><code>*int...</code>, <code>*uint...</code>, <code>*float...</code></td><td>NUMERIC</td><td><code>nil</code> stored as <code>0</code></td></tr><tr><td><code>string</code>, <code>*string</code></td><td>TEXT</td><td><code>nil</code> stored as <code>NULL</code></td></tr><tr><td><code>bool</code>, <code>*bool</code></td><td>NUMERIC</td><td>stored as <code>0</code> or <code>1</code></td></tr><tr><td><code>time.Time</code>, <code>*time.Time</code></td><td>NUMERIC</td><td>stored as unix timestamp, <code>nil</code> as <code>0</code></td></tr><tr><td><code>fluxaorm.Reference</code></td><td>NUMERIC</td><td><code>nil</code> as <code>0</code></td></tr><tr><td>enum, <code>[]enum</code></td><td>TAG</td><td><code>nil</code> as <code>NULL</code></td></tr></tbody></table><h2 id="running-index-alters" tabindex="-1"><a class="header-anchor" href="#running-index-alters"><span>Running Index Alters</span></a></h2><p>If at least one of your entities uses Redis Search, you must run <code>GetRedisSearchAlters()</code> when your application starts to create or update indexes:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">import</span> <span class="token string">&quot;github.com/latolukasz/fluxaorm/v2&quot;</span></span>
<span class="line"></span>
<span class="line">alters<span class="token punctuation">,</span> err <span class="token operator">:=</span> fluxaorm<span class="token punctuation">.</span><span class="token function">GetRedisSearchAlters</span><span class="token punctuation">(</span>ctx<span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token function">panic</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token keyword">for</span> <span class="token boolean">_</span><span class="token punctuation">,</span> alter <span class="token operator">:=</span> <span class="token keyword">range</span> alters <span class="token punctuation">{</span></span>
<span class="line">    err <span class="token operator">=</span> alter<span class="token punctuation">.</span><span class="token function">Exec</span><span class="token punctuation">(</span>ctx<span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token function">panic</span><span class="token punctuation">(</span>err<span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container warning"><p class="hint-container-title">Warning</p><p>If <code>alter.Exec(ctx)</code> modifies the current index (e.g., adds a new field), the previous index is dropped and a new one is created. The new index is then filled with entity data from MySQL. If the entity table contains many rows (hundreds of thousands or more), this operation can take some time.</p></div><h2 id="reindexing" tabindex="-1"><a class="header-anchor" href="#reindexing"><span>Reindexing</span></a></h2><p>FluxaORM automatically updates the Redis Search index when you add, update, or delete an entity via <code>Flush()</code>, <code>FlushAsync(true)</code>, or <code>FlushAsync(false)</code>. However, if your Redis index data was manually removed or MySQL data was manually updated, you can trigger a full reindex using the Provider&#39;s <code>ReindexRedisSearch()</code> method:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">err <span class="token operator">:=</span> ProductProvider<span class="token punctuation">.</span><span class="token function">ReindexRedisSearch</span><span class="token punctuation">(</span>ctx<span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// handle error</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>This scans all rows in MySQL and rebuilds the Redis Search hashes. For large tables, this operation can take some time.</p><h2 id="building-search-queries" tabindex="-1"><a class="header-anchor" href="#building-search-queries"><span>Building Search Queries</span></a></h2><p>Use <code>fluxaorm.NewRedisSearchWhere()</code> to build Redis Search query conditions:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">import</span> <span class="token string">&quot;github.com/latolukasz/fluxaorm/v2&quot;</span></span>
<span class="line"></span>
<span class="line">where <span class="token operator">:=</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewRedisSearchWhere</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>An empty <code>RedisSearchWhere</code> matches all documents (equivalent to <code>*</code> in Redis Search syntax).</p><h3 id="numeric-conditions" tabindex="-1"><a class="header-anchor" href="#numeric-conditions"><span>Numeric Conditions</span></a></h3><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token comment">// Exact match: Age = 25</span></span>
<span class="line">where <span class="token operator">:=</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewRedisSearchWhere</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">NumericEqual</span><span class="token punctuation">(</span><span class="token string">&quot;Age&quot;</span><span class="token punctuation">,</span> <span class="token number">25</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Range: Age between 18 and 65</span></span>
<span class="line">where <span class="token operator">=</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewRedisSearchWhere</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">NumericRange</span><span class="token punctuation">(</span><span class="token string">&quot;Age&quot;</span><span class="token punctuation">,</span> <span class="token number">18</span><span class="token punctuation">,</span> <span class="token number">65</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Minimum: Age &gt;= 18</span></span>
<span class="line">where <span class="token operator">=</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewRedisSearchWhere</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">NumericMin</span><span class="token punctuation">(</span><span class="token string">&quot;Age&quot;</span><span class="token punctuation">,</span> <span class="token number">18</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Maximum: Price &lt;= 99.99</span></span>
<span class="line">where <span class="token operator">=</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewRedisSearchWhere</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">NumericMax</span><span class="token punctuation">(</span><span class="token string">&quot;Price&quot;</span><span class="token punctuation">,</span> <span class="token number">99.99</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="tag-conditions" tabindex="-1"><a class="header-anchor" href="#tag-conditions"><span>Tag Conditions</span></a></h3><p>Tag conditions match exact values. You can provide multiple values (OR logic):</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token comment">// Status is &quot;active&quot;</span></span>
<span class="line">where <span class="token operator">:=</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewRedisSearchWhere</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Tag</span><span class="token punctuation">(</span><span class="token string">&quot;Status&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;active&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Status is &quot;active&quot; OR &quot;pending&quot;</span></span>
<span class="line">where <span class="token operator">=</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewRedisSearchWhere</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Tag</span><span class="token punctuation">(</span><span class="token string">&quot;Status&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;active&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;pending&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="text-conditions" tabindex="-1"><a class="header-anchor" href="#text-conditions"><span>Text Conditions</span></a></h3><p>Text conditions perform full-text search on TEXT fields:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token comment">// Full-text search on Name</span></span>
<span class="line">where <span class="token operator">:=</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewRedisSearchWhere</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Text</span><span class="token punctuation">(</span><span class="token string">&quot;Name&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;alice&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="boolean-conditions" tabindex="-1"><a class="header-anchor" href="#boolean-conditions"><span>Boolean Conditions</span></a></h3><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token comment">// Active = true</span></span>
<span class="line">where <span class="token operator">:=</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewRedisSearchWhere</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Bool</span><span class="token punctuation">(</span><span class="token string">&quot;Active&quot;</span><span class="token punctuation">,</span> <span class="token boolean">true</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Active = false</span></span>
<span class="line">where <span class="token operator">=</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewRedisSearchWhere</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Bool</span><span class="token punctuation">(</span><span class="token string">&quot;Active&quot;</span><span class="token punctuation">,</span> <span class="token boolean">false</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="combining-conditions" tabindex="-1"><a class="header-anchor" href="#combining-conditions"><span>Combining Conditions</span></a></h3><p>Multiple conditions are combined with AND logic (space-separated in Redis Search syntax). Chain the builder methods:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">where <span class="token operator">:=</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewRedisSearchWhere</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span></span>
<span class="line">    <span class="token function">NumericMin</span><span class="token punctuation">(</span><span class="token string">&quot;Age&quot;</span><span class="token punctuation">,</span> <span class="token number">18</span><span class="token punctuation">)</span><span class="token punctuation">.</span></span>
<span class="line">    <span class="token function">Tag</span><span class="token punctuation">(</span><span class="token string">&quot;Status&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;active&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span></span>
<span class="line">    <span class="token function">NumericMax</span><span class="token punctuation">(</span><span class="token string">&quot;Price&quot;</span><span class="token punctuation">,</span> <span class="token number">100</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="sorting" tabindex="-1"><a class="header-anchor" href="#sorting"><span>Sorting</span></a></h3><p>Use <code>SortBy()</code> to sort results by a sortable field:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token comment">// Sort by Age ascending</span></span>
<span class="line">where <span class="token operator">:=</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewRedisSearchWhere</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span></span>
<span class="line">    <span class="token function">NumericMin</span><span class="token punctuation">(</span><span class="token string">&quot;Age&quot;</span><span class="token punctuation">,</span> <span class="token number">18</span><span class="token punctuation">)</span><span class="token punctuation">.</span></span>
<span class="line">    <span class="token function">SortBy</span><span class="token punctuation">(</span><span class="token string">&quot;Age&quot;</span><span class="token punctuation">,</span> <span class="token boolean">true</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// Sort by Price descending</span></span>
<span class="line">where <span class="token operator">=</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewRedisSearchWhere</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span></span>
<span class="line">    <span class="token function">Tag</span><span class="token punctuation">(</span><span class="token string">&quot;Status&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;active&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span></span>
<span class="line">    <span class="token function">SortBy</span><span class="token punctuation">(</span><span class="token string">&quot;Price&quot;</span><span class="token punctuation">,</span> <span class="token boolean">false</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container tip"><p class="hint-container-title">Tips</p><p>Only fields with the <code>sortable</code> tag can be used in <code>SortBy()</code>.</p></div><h2 id="searching-for-entities" tabindex="-1"><a class="header-anchor" href="#searching-for-entities"><span>Searching for Entities</span></a></h2><p>Use the <code>SearchInRedis()</code> method on the Provider to find entities using the Redis Search index:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">import</span> <span class="token string">&quot;github.com/latolukasz/fluxaorm/v2&quot;</span></span>
<span class="line"></span>
<span class="line">where <span class="token operator">:=</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewRedisSearchWhere</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span></span>
<span class="line">    <span class="token function">NumericMin</span><span class="token punctuation">(</span><span class="token string">&quot;Age&quot;</span><span class="token punctuation">,</span> <span class="token number">18</span><span class="token punctuation">)</span><span class="token punctuation">.</span></span>
<span class="line">    <span class="token function">SortBy</span><span class="token punctuation">(</span><span class="token string">&quot;Age&quot;</span><span class="token punctuation">,</span> <span class="token boolean">true</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">products<span class="token punctuation">,</span> err <span class="token operator">:=</span> ProductProvider<span class="token punctuation">.</span><span class="token function">SearchInRedis</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> where<span class="token punctuation">,</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewPager</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">100</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// handle error</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token keyword">for</span> <span class="token boolean">_</span><span class="token punctuation">,</span> product <span class="token operator">:=</span> <span class="token keyword">range</span> products <span class="token punctuation">{</span></span>
<span class="line">    fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;Product: %s, Price: %.2f\\n&quot;</span><span class="token punctuation">,</span> product<span class="token punctuation">.</span><span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> product<span class="token punctuation">.</span><span class="token function">GetPrice</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>The <code>Pager</code> argument is optional. Pass <code>nil</code> to retrieve all matching results (up to 10,000):</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">products<span class="token punctuation">,</span> err <span class="token operator">:=</span> ProductProvider<span class="token punctuation">.</span><span class="token function">SearchInRedis</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> where<span class="token punctuation">,</span> <span class="token boolean">nil</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>Signature:</strong></p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>p XxxProvider<span class="token punctuation">)</span> <span class="token function">SearchInRedis</span><span class="token punctuation">(</span>ctx fluxaorm<span class="token punctuation">.</span>Context<span class="token punctuation">,</span> where <span class="token operator">*</span>fluxaorm<span class="token punctuation">.</span>RedisSearchWhere<span class="token punctuation">,</span> pager <span class="token operator">*</span>fluxaorm<span class="token punctuation">.</span>Pager<span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token operator">*</span>XxxEntity<span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="searching-with-total-count" tabindex="-1"><a class="header-anchor" href="#searching-with-total-count"><span>Searching with Total Count</span></a></h2><p>Use <code>SearchInRedisWithCount()</code> to get both the results and the total number of matching documents:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">products<span class="token punctuation">,</span> total<span class="token punctuation">,</span> err <span class="token operator">:=</span> ProductProvider<span class="token punctuation">.</span><span class="token function">SearchInRedisWithCount</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> where<span class="token punctuation">,</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewPager</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">100</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// handle error</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line">fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;Showing %d of %d total products\\n&quot;</span><span class="token punctuation">,</span> <span class="token function">len</span><span class="token punctuation">(</span>products<span class="token punctuation">)</span><span class="token punctuation">,</span> total<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Signature:</strong></p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>p XxxProvider<span class="token punctuation">)</span> <span class="token function">SearchInRedisWithCount</span><span class="token punctuation">(</span>ctx fluxaorm<span class="token punctuation">.</span>Context<span class="token punctuation">,</span> where <span class="token operator">*</span>fluxaorm<span class="token punctuation">.</span>RedisSearchWhere<span class="token punctuation">,</span> pager <span class="token operator">*</span>fluxaorm<span class="token punctuation">.</span>Pager<span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token operator">*</span>XxxEntity<span class="token punctuation">,</span> <span class="token builtin">int</span><span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="searching-for-a-single-entity" tabindex="-1"><a class="header-anchor" href="#searching-for-a-single-entity"><span>Searching for a Single Entity</span></a></h2><p>Use <code>SearchOneInRedis()</code> to retrieve a single matching entity:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">product<span class="token punctuation">,</span> found<span class="token punctuation">,</span> err <span class="token operator">:=</span> ProductProvider<span class="token punctuation">.</span><span class="token function">SearchOneInRedis</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewRedisSearchWhere</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">NumericEqual</span><span class="token punctuation">(</span><span class="token string">&quot;Age&quot;</span><span class="token punctuation">,</span> <span class="token number">25</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// handle error</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token keyword">if</span> <span class="token operator">!</span>found <span class="token punctuation">{</span></span>
<span class="line">    fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;Product not found&quot;</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">return</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line">fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;Found product: %s\\n&quot;</span><span class="token punctuation">,</span> product<span class="token punctuation">.</span><span class="token function">GetName</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container tip"><p class="hint-container-title">Tips</p><p>This method always uses <code>LIMIT 0 1</code>. If more than one document matches, only the first is returned.</p></div><p><strong>Signature:</strong></p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>p XxxProvider<span class="token punctuation">)</span> <span class="token function">SearchOneInRedis</span><span class="token punctuation">(</span>ctx fluxaorm<span class="token punctuation">.</span>Context<span class="token punctuation">,</span> where <span class="token operator">*</span>fluxaorm<span class="token punctuation">.</span>RedisSearchWhere<span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token operator">*</span>XxxEntity<span class="token punctuation">,</span> <span class="token builtin">bool</span><span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="searching-for-primary-keys" tabindex="-1"><a class="header-anchor" href="#searching-for-primary-keys"><span>Searching for Primary Keys</span></a></h2><p>If you only need entity IDs, use <code>SearchIDsInRedis()</code>:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">ids<span class="token punctuation">,</span> err <span class="token operator">:=</span> ProductProvider<span class="token punctuation">.</span><span class="token function">SearchIDsInRedis</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewRedisSearchWhere</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">NumericMin</span><span class="token punctuation">(</span><span class="token string">&quot;Price&quot;</span><span class="token punctuation">,</span> <span class="token number">50</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token boolean">nil</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// handle error</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"><span class="token keyword">for</span> <span class="token boolean">_</span><span class="token punctuation">,</span> id <span class="token operator">:=</span> <span class="token keyword">range</span> ids <span class="token punctuation">{</span></span>
<span class="line">    fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;Product ID: %d\\n&quot;</span><span class="token punctuation">,</span> id<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Signature:</strong></p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>p XxxProvider<span class="token punctuation">)</span> <span class="token function">SearchIDsInRedis</span><span class="token punctuation">(</span>ctx fluxaorm<span class="token punctuation">.</span>Context<span class="token punctuation">,</span> where <span class="token operator">*</span>fluxaorm<span class="token punctuation">.</span>RedisSearchWhere<span class="token punctuation">,</span> pager <span class="token operator">*</span>fluxaorm<span class="token punctuation">.</span>Pager<span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token builtin">uint64</span><span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>With total count:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">ids<span class="token punctuation">,</span> total<span class="token punctuation">,</span> err <span class="token operator">:=</span> ProductProvider<span class="token punctuation">.</span><span class="token function">SearchIDsInRedisWithCount</span><span class="token punctuation">(</span>ctx<span class="token punctuation">,</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewRedisSearchWhere</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Tag</span><span class="token punctuation">(</span><span class="token string">&quot;Status&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;active&quot;</span><span class="token punctuation">)</span><span class="token punctuation">,</span> fluxaorm<span class="token punctuation">.</span><span class="token function">NewPager</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token number">50</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// handle error</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line">fmt<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;Found %d IDs out of %d total\\n&quot;</span><span class="token punctuation">,</span> <span class="token function">len</span><span class="token punctuation">(</span>ids<span class="token punctuation">)</span><span class="token punctuation">,</span> total<span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Signature:</strong></p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>p XxxProvider<span class="token punctuation">)</span> <span class="token function">SearchIDsInRedisWithCount</span><span class="token punctuation">(</span>ctx fluxaorm<span class="token punctuation">.</span>Context<span class="token punctuation">,</span> where <span class="token operator">*</span>fluxaorm<span class="token punctuation">.</span>RedisSearchWhere<span class="token punctuation">,</span> pager <span class="token operator">*</span>fluxaorm<span class="token punctuation">.</span>Pager<span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token builtin">uint64</span><span class="token punctuation">,</span> <span class="token builtin">int</span><span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="summary" tabindex="-1"><a class="header-anchor" href="#summary"><span>Summary</span></a></h2><table><thead><tr><th>Method</th><th>Returns</th><th>Description</th></tr></thead><tbody><tr><td><code>SearchInRedis</code></td><td><code>([]*XxxEntity, error)</code></td><td>Entities matching the query</td></tr><tr><td><code>SearchInRedisWithCount</code></td><td><code>([]*XxxEntity, int, error)</code></td><td>Entities + total count</td></tr><tr><td><code>SearchOneInRedis</code></td><td><code>(*XxxEntity, bool, error)</code></td><td>Single entity (LIMIT 1)</td></tr><tr><td><code>SearchIDsInRedis</code></td><td><code>([]uint64, error)</code></td><td>Primary keys only</td></tr><tr><td><code>SearchIDsInRedisWithCount</code></td><td><code>([]uint64, int, error)</code></td><td>Primary keys + total count</td></tr></tbody></table><h3 id="redissearchwhere-builder-methods" tabindex="-1"><a class="header-anchor" href="#redissearchwhere-builder-methods"><span>RedisSearchWhere Builder Methods</span></a></h3><table><thead><tr><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><code>NumericEqual(field, value)</code></td><td>Exact numeric match</td></tr><tr><td><code>NumericRange(field, min, max)</code></td><td>Numeric range (inclusive)</td></tr><tr><td><code>NumericMin(field, min)</code></td><td>Greater than or equal to</td></tr><tr><td><code>NumericMax(field, max)</code></td><td>Less than or equal to</td></tr><tr><td><code>Tag(field, values...)</code></td><td>Exact tag match (OR for multiple values)</td></tr><tr><td><code>Text(field, query)</code></td><td>Full-text search</td></tr><tr><td><code>Bool(field, value)</code></td><td>Boolean match</td></tr><tr><td><code>SortBy(field, ascending)</code></td><td>Sort results by a sortable field</td></tr></tbody></table>`,73)]))}const l=s(o,[["render",p]]),u=JSON.parse('{"path":"/guide/redis_search.html","title":"Redis Search","lang":"en-US","frontmatter":{},"git":{"updatedTime":1772457520000,"contributors":[{"name":"Lukasz Lato","username":"","email":"latolukasz@gmail.com","commits":18},{"name":"lukaszjezapkowicz","username":"lukaszjezapkowicz","email":"ljezapkowicz@gamesture.com","commits":1,"url":"https://github.com/lukaszjezapkowicz"},{"name":"lukaszlato","username":"lukaszlato","email":"latolukasz@gmail.com","commits":7,"url":"https://github.com/lukaszlato"}],"changelog":[{"hash":"c7abb617d848487b26523673384942aaa8151e75","time":1772457520000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"Lifecycle callbacks"},{"hash":"456e3bba4fa5c1476f9974b418e090017f6b0cc2","time":1772273114000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"New ORM"},{"hash":"bfc685f185295c4935fe51069bacb3c93ec9beda","time":1764664948000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"ac3c7a4049f590ca583607fc7c744e1064025cf1","time":1762959222000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"cc4f007ff11dc6f9ac43ee2b06218d410d0f9632","time":1761821772000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"54896f2c19b7c6363a23af47d6b5dba8f5dd92e9","time":1761666366000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"5c392e940df949dc8611b810fbe840a7890e32c2","time":1761651895000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"04307b13b2ff0207c22fe3684c9e5935ec4a9f44","time":1754854253000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"fluxaorm"},{"hash":"9a00ca9d194375517fdcacf6f1b9c9f5b42b65e4","time":1668013756000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"removed redis search"},{"hash":"3565d4203624a269e3ced947a666e4258776d437","time":1660209586000,"email":"ljezapkowicz@gamesture.com","author":"lukaszjezapkowicz","message":"typos part 2"},{"hash":"f23aafd4cefaa8c41c0972ff1643eef02453d3ef","time":1630404192000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"5d9542ffa89ca8653b05e000f9d45efae1438dc0","time":1630330877000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"ab2ad53b6a534be4cba3768ed94da50630c75a0b","time":1629702328000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"5fb4f17197ce9f87dc3503e45d4f07b689acec77","time":1628599752000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"1a84fe401aac546f204f5a30104fd0813d783458","time":1628088902000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"ab728e0dd8edfac5b3507749f803b9a5a8084c31","time":1627808149000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"9841f6d52012fe88c7dac22a0bd8554d24ba3bf8","time":1626859263000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"4b5144cfd4b964c9eb30b6d17921cee6669b218a","time":1626793834000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"69122770a0c24d67072cf618350ea0bdfcf09354","time":1626790635000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"d2c133725fd6a881fd685c0470a3b7f7ebaa5abc","time":1626790075000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"3a7a9fb05e606b1a39c38a7b2ecf443a0063b3ce","time":1626769596000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"21bc91382ab67fa9c33a89d1d1f2855a9365f766","time":1626710252000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"a1e1c7a10bf48e33322dd7d89af03472c2e42fa7","time":1626702488000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"4a0baec42b0605a2c6dcf4d3f1cca004aaf212e1","time":1626699158000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"75ca86878ab9f1b034ce1c825899a3cdca85a465","time":1626348088000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"},{"hash":"1ca147c43a9022da02349a3e050b6ec658f4eda4","time":1625562292000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"favicon"}]},"filePathRelative":"guide/redis_search.md"}');export{l as comp,u as data};
